#include "interface.h"
#include <cuda_runtime.h>

namespace {

constexpr int TILE_DIM = 32;

__global__ void transpose_kernel(const float* __restrict__ input, float* __restrict__ output, int width, int height) {
    __shared__ float tile[TILE_DIM][TILE_DIM + 1];

    int x_out = blockIdx.x * TILE_DIM + threadIdx.x;
    int y_out = blockIdx.y * TILE_DIM + threadIdx.y;

    int x_in = y_out;
    int y_in = x_out;

    bool in_valid = (x_in < width && y_in < height);
    tile[threadIdx.y][threadIdx.x] = in_valid ? input[y_in * width + x_in] : 0.0f;
    __syncthreads();

    if (x_out < height && y_out < width) {
        output[y_out * height + x_out] = tile[threadIdx.x][threadIdx.y];
    }
}

}  // namespace

void transpose_f32(const float* input, float* output, int width, int height, int iters) {
    dim3 block(TILE_DIM, TILE_DIM);
    dim3 grid((height + TILE_DIM - 1) / TILE_DIM, (width + TILE_DIM - 1) / TILE_DIM);

    for (int iter = 0; iter < iters; ++iter) {
        transpose_kernel<<<grid, block>>>(input, output, width, height);
    }
}
